async def import_parts(conn: asyncpg.Connection) -> dict:
    inserted = 0
    skipped = 0
    seen_sku: set = set()

    for pn, eng_name, heb_desc, price_ils, model, category in PARTS:
        sku = f"GEELY-{re.sub(chr(91) + r'^A-Z0-9' + chr(93), '-', pn.upper())}"
        if sku in seen_sku:
            skipped += 1
            continue
        seen_sku.add(sku)

        # price_ils is excl. VAT from Geely Israel catalog; normalize to 18% IL VAT
        il_retail = round(price_ils * 1.18, 2)
        desc = f"{eng_name}. Model: {model}. Israeli OEM retail price (incl. VAT): {il_retail} ILS."

        try:
            async with conn.transaction():
                pid = await conn.fetchval("""
                    INSERT INTO parts_catalog(
                        id, sku, oem_number, name, manufacturer, manufacturer_id,
                        category, description, specifications,
                        base_price, importer_price_ils, min_price_ils, max_price_ils,
                        part_type, is_safety_critical, needs_oem_lookup,
                        master_enriched, is_active, created_at, updated_at
                    ) VALUES (
                        gen_random_uuid(), $1, $2, $3, 'Geely', $4::uuid,
                        $5, $6, '{}'::jsonb,
                        $7, 0, $7, $7,
                        'original', FALSE, FALSE,
                        FALSE, TRUE, NOW(), NOW()
                    )
                    ON CONFLICT (sku) DO UPDATE SET
                        name = EXCLUDED.name,
                        base_price = EXCLUDED.base_price,
                        importer_price_ils = 0,
                        min_price_ils = EXCLUDED.min_price_ils,
                        max_price_ils = EXCLUDED.max_price_ils,
                        updated_at = NOW()
                    RETURNING id
                """, sku, pn, eng_name[:255], GEELY_BRAND_ID,
                     category, desc[:500], il_retail)
                if pid:
                    inserted += 1
        except Exception as e:
            log.warning("Failed %s: %s", sku, e)
            skipped += 1

    return {"inserted": inserted, "skipped": skipped}


async def main() -> None:
    conn = await asyncpg.connect(DB_DSN)
    try:
        log.info("Starting Geely Israel price list import (%d parts)...", len(PARTS))
        result = await import_parts(conn)
        count = await conn.fetchval(
            "SELECT COUNT(*) FROM parts_catalog WHERE manufacturer='Geely' AND is_active=TRUE"
        )
        log.info("Done: inserted=%d skipped=%d | DB total Geely=%d",
                 result["inserted"], result["skipped"], count)
    finally:
        await conn.close()


if __name__ == "__main__":
    asyncio.run(main())

